import{_ as t,o,c as n,ag as i}from"./chunks/framework.DUvHsH_U.js";const d=JSON.parse('{"title":"Promotional Offers and Mobile Banners Setup","description":"","frontmatter":{},"headers":[],"relativePath":"offers-loyalty/promotional-offers-mobile-banners-setup.md","filePath":"offers-loyalty/promotional-offers-mobile-banners-setup.md","lastUpdated":1777975835000}'),r={name:"offers-loyalty/promotional-offers-mobile-banners-setup.md"};function l(s,e,a,h,g,p){return o(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="promotional-offers-and-mobile-banners-setup" tabindex="-1">Promotional Offers and Mobile Banners Setup <a class="header-anchor" href="#promotional-offers-and-mobile-banners-setup" aria-label="Permalink to &quot;Promotional Offers and Mobile Banners Setup&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This setup controls the promotional sliders that appear on the mobile app home screen and category pages.</p><p>When this setup is correct, testers will see active banners in the correct slider location, can tap banners to open the related offer products, and will see discount or free-item behavior when adding eligible products to the cart.</p><h2 id="erpnext-setup-steps" tabindex="-1">ERPNext Setup Steps <a class="header-anchor" href="#erpnext-setup-steps" aria-label="Permalink to &quot;ERPNext Setup Steps&quot;">​</a></h2><ol><li><p><strong>Log in as an Administrator</strong></p><ul><li>Open the ERPNext admin dashboard.</li><li>Log in with a System Manager or Administrator account.</li></ul></li><li><p><strong>Allow guests to read mobile banners</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <code>Role Permission Manager</code> and open it.</li><li>In the <strong>Document Type</strong> field, select <code>Mobile Banner</code>.</li><li>Find or add a row for the <strong>Guest</strong> role.</li><li>Check the <strong>Read</strong> box for the <strong>Guest</strong> role.</li><li>Click <strong>Update</strong> or <strong>Save</strong>.</li></ul></li><li><p><strong>Allow customers to read mobile banners</strong></p><ul><li>Stay in <strong>Role Permission Manager</strong>.</li><li>Confirm the <strong>Document Type</strong> field is still set to <code>Mobile Banner</code>.</li><li>Find or add a row for the <strong>Customer</strong> role.</li><li>Check the <strong>Read</strong> box for the <strong>Customer</strong> role.</li><li>Click <strong>Update</strong> or <strong>Save</strong>.</li></ul></li><li><p><strong>Open the mobile e-commerce control panel</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <code>Mobile e-commerce control panel</code> and open it.</li><li>Go to the <strong>Banners</strong> section.</li><li>Click <strong>Create banner</strong>.</li><li>A banner configuration dialog should open.</li></ul></li><li><p><strong>Fill the banner dates and status</strong></p><ul><li>Set <strong>Valid From</strong> to today or an earlier date.</li><li>Set <strong>Valid To</strong> to today or a future date.</li><li>Make sure the current testing date falls between <strong>Valid From</strong> and <strong>Valid To</strong>.</li><li>Make sure the <strong>Disabled</strong> checkbox is <strong>unchecked</strong>.</li></ul></li><li><p><strong>Fill the banner content</strong></p><ul><li>Enter the banner <strong>Title</strong> in English.</li><li>Enter the banner <strong>Title</strong> in Arabic.</li><li>Enter the banner <strong>Subtitle</strong> in English.</li><li>Enter the banner <strong>Subtitle</strong> in Arabic.</li><li>Upload or select the banner image.</li><li>Select the <strong>Subtitle Position</strong>: <ul><li><strong>Center</strong> to show the subtitle centered when the offer screen is opened.</li><li><strong>Left</strong> to show the subtitle on the left side when the offer screen is opened.</li><li><strong>Right</strong> to show the subtitle on the right side when the offer screen is opened.</li></ul></li></ul></li><li><p><strong>Choose where the banner appears</strong></p><ul><li>To show the banner in the top home screen slider, check <strong>Show in top home page</strong>.</li><li>To show the banner in the bottom home screen slider, check <strong>Show in bottom home page</strong>.</li><li>To show the banner on a category page, check <strong>Show in main category</strong>.</li><li>If you checked <strong>Show in main category</strong>, select the required item category in the category field.</li><li>Use the <strong>Ranking</strong> field to control the banner order in the slider.</li><li>Use a smaller ranking number for banners that should appear earlier.</li></ul></li><li><p><strong>Create a normal banner</strong></p><ul><li>In the banner type field, select <strong>Normal</strong>.</li><li>Go to the <strong>Qualified Items</strong> table.</li><li>Add the products that should open when the tester taps the banner.</li><li>Save the banner.</li><li>In the mobile app, the banner should appear in the selected slider location. When the tester taps it, the app should open the related products.</li></ul></li><li><p><strong>Create a percentage discount banner</strong></p><ul><li>In the banner type field, select <strong>Discount</strong>.</li><li>Enter the discount percentage in the <strong>Discount</strong> field.</li><li>Go to the <strong>Qualified Items</strong> table.</li><li>Add the products that receive the discount.</li><li>Save the banner.</li><li>In the mobile app, the banner should appear in the selected slider location. When the tester opens the banner products, eligible products should show and calculate with the configured discount.</li></ul></li><li><p><strong>Create a buy X get Y free banner</strong></p><ul><li>In the banner type field, select <strong>Free items</strong>.</li><li>Fill <strong>Qty of qualified items</strong>.</li><li>Fill <strong>UOM of qualified items</strong>.</li><li>Fill <strong>Number of free items</strong>.</li><li>Fill <strong>UOM of free items</strong>.</li><li>Go to the <strong>Qualified Items</strong> table.</li><li>Add the products the customer must buy.</li><li>Go to the <strong>Free Items</strong> table.</li><li>Add the products the customer can receive for free.</li><li>Save the banner.</li><li>In the mobile app, the banner should appear in the selected slider location. When the tester adds enough qualified products to the cart using the configured unit of measure, the app should show that free items are available.</li></ul></li><li><p><strong>Test from the mobile app</strong></p><ul><li>Fully close and reopen the mobile app.</li><li>Open the home screen.</li><li>Confirm the top and bottom home page banners appear in their selected locations.</li><li>Open the relevant category page.</li><li>Confirm category banners appear only on the selected category page.</li><li>Tap a banner that has products in the <strong>Qualified Items</strong> table.</li><li>Confirm the app opens the related offer products.</li><li>For discount offers, add a qualified product and confirm the discounted price is used.</li><li>For free-item offers, add enough qualified products and confirm the app shows the available free items.</li></ul></li></ol><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ol><li><p><strong>If the banner is not showing on the home screen</strong></p><ul><li>This usually means the banner is not active for the testing date or it was not placed on the home screen.</li><li>Open <strong>Mobile e-commerce control panel</strong>.</li><li>Go to the <strong>Banners</strong> section.</li><li>Open the banner.</li><li>Confirm the testing date is between <strong>Valid From</strong> and <strong>Valid To</strong>.</li><li>Confirm the <strong>Disabled</strong> checkbox is unchecked.</li><li>Confirm <strong>Show in top home page</strong> or <strong>Show in bottom home page</strong> is checked.</li><li>Save the banner.</li><li>Fully close and reopen the mobile app, then check the home screen again.</li></ul></li><li><p><strong>If the banner is not showing on the category page</strong></p><ul><li>This usually means the banner was not connected to the category being tested.</li><li>Open <strong>Mobile e-commerce control panel</strong>.</li><li>Go to the <strong>Banners</strong> section.</li><li>Open the banner.</li><li>Confirm <strong>Show in main category</strong> is checked.</li><li>Confirm the selected category exactly matches the category page opened in the mobile app.</li><li>Save the banner.</li><li>Fully close and reopen the mobile app, then open the category page again.</li></ul></li><li><p><strong>If the banner is at the end of the list instead of the beginning</strong></p><ul><li>This means the banner order needs to be adjusted.</li><li>Open <strong>Mobile e-commerce control panel</strong>.</li><li>Go to the <strong>Banners</strong> section.</li><li>Open the banner.</li><li>Lower the <strong>Ranking</strong> number for banners that should appear earlier.</li><li>Save the banner.</li><li>Fully close and reopen the mobile app, then check the slider again.</li></ul></li><li><p><strong>If tapping the banner does nothing</strong></p><ul><li>This usually means no products were added to the banner.</li><li>Open <strong>Mobile e-commerce control panel</strong>.</li><li>Go to the <strong>Banners</strong> section.</li><li>Open the banner.</li><li>Add at least one product to the <strong>Qualified Items</strong> table.</li><li>Save the banner.</li><li>Fully close and reopen the mobile app, then tap the banner again.</li></ul></li><li><p><strong>If a discount offer does not reduce the product price</strong></p><ul><li>This usually means the discount value or product list is incomplete.</li><li>Open <strong>Mobile e-commerce control panel</strong>.</li><li>Go to the <strong>Banners</strong> section.</li><li>Open the discount banner.</li><li>Confirm the banner type is <strong>Discount</strong>.</li><li>Confirm the <strong>Discount</strong> field has the correct percentage.</li><li>Confirm the product is listed in the <strong>Qualified Items</strong> table.</li><li>Save the banner.</li><li>Fully close and reopen the mobile app, then test the product again.</li></ul></li><li><p><strong>If a free items offer is not calculating correctly in the app</strong></p><ul><li>This usually means the required quantity or unit fields are missing, or the item tables are incomplete.</li><li>Open <strong>Mobile e-commerce control panel</strong>.</li><li>Go to the <strong>Banners</strong> section.</li><li>Open the free-items banner.</li><li>Confirm <strong>Qty of qualified items</strong> is filled.</li><li>Confirm <strong>UOM of qualified items</strong> is filled.</li><li>Confirm <strong>Number of free items</strong> is filled.</li><li>Confirm <strong>UOM of free items</strong> is filled.</li><li>Confirm the <strong>Qualified Items</strong> table contains the products the customer must buy.</li><li>Confirm the <strong>Free Items</strong> table contains the products the customer can receive for free.</li><li>Save the banner.</li><li>Fully close and reopen the mobile app, then test the offer again.</li></ul></li><li><p><strong>If the banner appears, but some products are missing after tapping it</strong></p><ul><li>This usually means the missing products are not available for the selected customer or setup.</li><li>Open the banner from the <strong>Banners</strong> section.</li><li>Confirm the missing products are listed in <strong>Qualified Items</strong>.</li><li>Confirm those products are enabled and available for sale in ERPNext.</li><li>Confirm the products have the required stock, price, and unit setup for this client.</li><li>Save any changes, then test again in the mobile app.</li></ul></li></ol>',8)])])}const u=t(r,[["render",l]]);export{d as __pageData,u as default};
